import base64
import zlib
import urllib.parse
import requests
from xml.sax.saxutils import escape

def build_saml_authn_request(destination_url, user_info):
    saml_request_template = """
    <samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
                        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
                        ID="_some_unique_id"
                        Version="2.0"
                        IssueInstant="2023-10-10T00:00:00Z"
                        Destination="{destination}">
        <saml:Issuer>{issuer}</saml:Issuer>
        <samlp:NameIDPolicy AllowCreate="true" Format="urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified"/>
    </samlp:AuthnRequest>
    """
    
    # Escape user-provided values to prevent XML injection
    destination = escape(destination_url)
    issuer = escape(user_info.get('issuer', 'default_issuer'))

    # Construct the SAML request
    saml_request = saml_request_template.format(destination=destination, issuer=issuer)

    # Compress and encode the SAML request
    deflated_request = zlib.compress(saml_request.encode('utf-8'))[2:-4]
    base64_request = base64.b64encode(deflated_request).decode('utf-8')
    encoded_request = urllib.parse.quote(base64_request)

    return encoded_request

def post_saml_request(destination_url, user_info):
    saml_request = build_saml_authn_request(destination_url, user_info)
    response = requests.post(destination_url, data={'SAMLRequest': saml_request})
    return response

